Bash(node -e "
const fs = require\('fs'\);
const path = require\('path'\);
const catDir = path.join\('src', 'data', 'categories'\);
const files = fs.readdirSync\(catDir\).filter\(f => f.endsWith\('.json'\)\);
console.log\('Category JSONs found:', files.length\);
let ok = 0;
for \(const f of files\) {
  try {
    const data = JSON.parse\(fs.readFileSync\(path.join\(catDir, f\), 'utf8'\)\);
    if \(data._meta && data._meta.scope\) { ok++; }
    else { console.log\('WARN: missing _meta.scope in', f\); }
  } catch \(e\) { console.log\('ERROR:', f, e.message\); }
}
console.log\('Valid:', ok + '/' + files.length\);
")
